hbs.a_button:
{{#if href}}<a
 href="{{href}}"{{else}}<span{{/if}}
 class="a_button {{style}}">
{{> a_icon icon=icon_before }}
<span>{{text}}</span>
{{> a_icon icon=icon_after }}
{{#if href}}</a>{{else}}</span>{{/if}}

hbs.a_icon:
{{#with a_icon}}
{{> a_icon }}
{{else}}
{{#if icon}}
<span class="a_icon"
 data-icon="{{icon}}"
 style="--icon: {{lucideSvgUrl icon fill stroke stroke_width}}"
 aria-hidden="true"></span>
{{/if}}
{{/with}}

hbs.a_image:
{{#if a_image.src}}
<{{#if a_image.href}}a href="{{a_image.href}}"{{else}}div{{/if}} class="a_image">
<img
 src="{{a_image.src}}"
 alt="{{a_image.alt}}"
 {{#if a_image.width}} width="{{parseInt a_image.width}}"{{/if}}
 {{#if a_image.height}} height="{{parseInt a_image.height}}"{{/if}}
{{#if a_image.loading}}
 loading="{{a_image.loading}}"
{{/if}}
 />
</{{#if a_image.href}}a{{else}}div{{/if}}>
{{/if}}

hbs.a_image_cover:
{{#if a_image_cover.src}}
<div class="a_image_cover">
<img
 src="{{a_image_cover.src}}"
 alt="{{a_image_cover.alt}}"
{{#if a_image_cover.width}}
 width="{{a_image_cover.width}}"
{{/if}}
{{#if a_image_cover.height}}
 height="{{a_image_cover.height}}"
{{/if}}
{{#if a_image_cover.loading}}
 loading="{{a_image_cover.loading}}"
{{/if}}
 />
</div>
{{/if}}

hbs.o_breadcrumbs:
{{#if items}}
<section class="o_breadcrumbs container" {{{sectionId}}}>
<nav aria-label="Breadcrumb">
{{#each items}}
{{#if href}}
<a href="{{href}}">{{text}}</a>
{{else}}
<span aria-current="page">{{text}}</span>
{{/if}}
{{/each}}
</nav>
<script type="application/ld+json">
{
"@context": "https://schema.org",
"@type": "BreadcrumbList",
"itemListElement": [
{{#each items}}
{
"@type": "ListItem",
"position": {{inc @index}},
"name": {{json text}}{{#if href}},
"item": {{json href}}{{/if}} }{{#unless @last}},{{/unless}}
{{/each}}
]
}
</script>
</section>
{{/if}}

hbs.o_design_images:
{{#unless ignore}}
<section class="o_design_images grid" {{{sectionId}}}>
{{> m_section_title }}

{{#each items}}
{{#unless ignore}}
<div class="col-6 design">
{{> a_image }}
{{#if tags}}
<div class="tags">
{{#each tags}}
<span class="tag">{{this}}</span>
{{/each}}
</div>
{{/if}}
</div>
{{/unless}}
{{/each}}
</section>
{{/unless}}

js.o_color_palette:
document.querySelectorAll('.o_color_palette .swatch').forEach(function(swatch) {
	swatch.addEventListener('click', function() {
		var hex = swatch.dataset.hex;
		navigator.clipboard.writeText(hex).then(function() {
			swatch.classList.add('copied');
			setTimeout(function() {
				swatch.classList.remove('copied');
			}, 1500);
		});
	});
});

js.o_header:
document.addEventListener('DOMContentLoaded', () => {
	let lastY = window.scrollY;
	let scrollUpDistance = 0;
	window.addEventListener('scroll', () => {
		var y = window.scrollY;
		if (y <= 128) {
			document.body.classList.remove('header_hidden');
			scrollUpDistance = 0;
		} else if (y < lastY) {
			scrollUpDistance += lastY - y;
			if (scrollUpDistance >= 64) {
				document.body.classList.remove('header_hidden');
			}
		} else {
			scrollUpDistance = 0;
			document.body.classList.add('header_hidden');
		}
		lastY = y;
	});

	/* Mobile menu */
	document.querySelectorAll('.o_header .menu-toggle').forEach((toggle) => {
		toggle.addEventListener('click', () => {
			var opened = document.body.classList.toggle('menu_opened');
			toggle.setAttribute('aria-expanded', opened);
		});
	});

	document.querySelectorAll('#main-nav a').forEach((link) => {
		link.addEventListener('click', () => {
			document.body.classList.remove('menu_opened');
		});
	});

	document.addEventListener('keydown', (e) => {
		if (e.key === 'Escape') {
			document.body.classList.remove('menu_opened');
		}
	});

	const themeButtons = document.querySelectorAll('.a_theme_toggle');
	const setTheme = (t) => {
		document.documentElement.classList.remove('light', 'dark', 'palette');
		document.documentElement.classList.add(t);
		localStorage.theme = t;
		themeButtons.forEach((btn) => {
			btn.classList.toggle('active', btn.dataset.theme === t);
		});
	};
	setTheme(localStorage.theme || 'palette');
	themeButtons.forEach((btn) => {
		btn.addEventListener('click', () => setTheme(btn.dataset.theme));
	});
});

js.o_style_guide:
document.querySelectorAll('.o_style_guide .principle img[alt]').forEach(function(img) {
	var principle = img.closest('.principle');
	var cover = img.closest('.a_image_cover');
	cover.setAttribute('data-prompt', img.alt);
	cover.addEventListener('click', function() {
		navigator.clipboard.writeText(img.alt).then(function() {
			principle.classList.add('copied');
			setTimeout(function() {
				principle.classList.remove('copied');
			}, 1500);
		});
	});
});

js.o_typography:
document.querySelectorAll('.o_typography .card').forEach(function(card) {
	card.addEventListener('click', function() {
		var css = card.dataset.css;
		if (!css) return;
		navigator.clipboard.writeText(css).then(function() {
			card.classList.add('copied');
			setTimeout(function() {
				card.classList.remove('copied');
			}, 1500);
		});
	});
});
